--
-- Table structure for table `customer_request_analysis`
--

DROP TABLE IF EXISTS `customer_request_analysis`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_request_analysis` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID dòng trạng thái',
  `request_case_id` bigint unsigned NOT NULL COMMENT 'Yêu cầu',
  `status_instance_id` bigint unsigned DEFAULT NULL COMMENT 'Instance trạng thái',
  `notes` text COMMENT 'Ghi chú',
  `created_by` bigint unsigned DEFAULT NULL COMMENT 'Người tạo',
  `updated_by` bigint unsigned DEFAULT NULL COMMENT 'Người cập nhật',
  `performer_user_id` bigint unsigned DEFAULT NULL COMMENT 'Người phân tích',
  `analysis_content` text COMMENT 'Nội dung phân tích',
  `analysis_completed_at` datetime DEFAULT NULL COMMENT 'Ngày hoàn thành phân tích',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_crs_836d871bf5_inst` (`status_instance_id`),
  KEY `idx_crs_836d871bf5_case` (`request_case_id`),
  KEY `customer_request_analysis_created_by_index` (`created_by`),
  KEY `customer_request_analysis_updated_by_index` (`updated_by`),
  KEY `customer_request_analysis_performer_user_id_index` (`performer_user_id`),
  CONSTRAINT `fk_crs_836d871bf5_case` FOREIGN KEY (`request_case_id`) REFERENCES `customer_request_cases` (`id`) ON DELETE CASCADE,
