DROP TABLE IF EXISTS `customer_request_status_instances`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_request_status_instances` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID instance trạng thái',
  `request_case_id` bigint unsigned NOT NULL COMMENT 'Yêu cầu',
  `status_code` varchar(80) NOT NULL COMMENT 'Mã trạng thái',
  `status_table` varchar(120) NOT NULL COMMENT 'Tên bảng trạng thái',
  `status_row_id` bigint unsigned DEFAULT NULL COMMENT 'ID dòng trạng thái thực tế',
  `previous_instance_id` bigint unsigned DEFAULT NULL COMMENT 'Instance trạng thái trước',
  `next_instance_id` bigint unsigned DEFAULT NULL COMMENT 'Instance trạng thái sau',
  `decision_context_code` varchar(80) DEFAULT NULL COMMENT 'Mã context decision nghiệp vụ',
  `decision_outcome_code` varchar(80) DEFAULT NULL COMMENT 'Kết quả chọn trong decision',
  `decision_source_status_code` varchar(80) DEFAULT NULL COMMENT 'Trạng thái nguồn phát sinh decision',
  `entered_at` datetime DEFAULT NULL COMMENT 'Thời điểm vào trạng thái',
  `exited_at` datetime DEFAULT NULL COMMENT 'Thời điểm rời trạng thái',
  `is_current` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Có phải trạng thái hiện tại',
  `created_by` bigint unsigned DEFAULT NULL COMMENT 'Người tạo instance',
  `updated_by` bigint unsigned DEFAULT NULL COMMENT 'Người cập nhật instance',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_customer_request_status_instances_case_status` (`request_case_id`,`status_code`),
  KEY `customer_request_status_instances_previous_instance_id_index` (`previous_instance_id`),
  KEY `customer_request_status_instances_next_instance_id_index` (`next_instance_id`),
  KEY `customer_request_status_instances_created_by_index` (`created_by`),
  KEY `customer_request_status_instances_updated_by_index` (`updated_by`),
  CONSTRAINT `fk_customer_request_status_instances_case` FOREIGN KEY (`request_case_id`) REFERENCES `customer_request_cases` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_customer_request_status_instances_created_by` FOREIGN KEY (`created_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_customer_request_status_instances_updated_by` FOREIGN KEY (`updated_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Chuỗi trạng thái thực tế của từng yêu cầu';
