--
-- Table structure for table `monthly_calendars`
--

DROP TABLE IF EXISTS `monthly_calendars`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `monthly_calendars` (
  `date` date NOT NULL,
  `year` smallint unsigned NOT NULL,
  `month` tinyint unsigned NOT NULL,
  `day` tinyint unsigned NOT NULL,
  `week_number` tinyint unsigned NOT NULL COMMENT 'Tuần trong năm (1-53)',
  `day_of_week` tinyint unsigned NOT NULL COMMENT '1: Chủ Nhật, 2: Thứ Hai, ..., 7: Thứ Bảy',
  `is_weekend` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'TRUE nếu Thứ Bảy hoặc Chủ Nhật',
  `is_working_day` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'TRUE = ngày làm việc bình thường',
  `is_holiday` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'TRUE = ngày nghỉ lễ chính thức',
  `holiday_name` varchar(200) DEFAULT NULL COMMENT 'Tên ngày lễ nếu có',
  `note` varchar(255) DEFAULT NULL COMMENT 'Ghi chú thêm',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`date`),
  KEY `idx_mc_year_month` (`year`,`month`),
  KEY `idx_mc_year_week` (`year`,`week_number`),
  KEY `idx_mc_updated` (`updated_at`),
  KEY `idx_mc_working_day` (`is_working_day`),
  KEY `idx_mc_holiday` (`is_holiday`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

