INSERT INTO `product_features` VALUES (1,'1ea2400a-1cd8-4ce2-8338-474d03d40316',18,1,'Đăng nhập','Chức năng cho phép người dùng sử dụng được cấp tài khoản trên hệ thống đăng nhập vào hệ thống để thực hiện các nghiệp vụ theo phạm vi được phân công theo phân quyền tài khoản. Chức năng Bệnh án gồm các tính năng:\n- Nhập thông tin tài khoản\n- Nhập thông tin kiểm tra hoặc OTP\n- Lưu mật khẩu khi đăng nhập\n- Đăng nhập vào hệ thống','ACTIVE',1,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(2,'9f165fad-cefd-4ef8-8280-a884f2111d84',18,1,'Trang chủ','Chức năng cho phép người dùng truy cập vào trang chủ của bệnh viện để kiểm tra các thông báo được bộ phân chức năng nhập thông tin thông báo trên hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin trang chủ của hệ thống\n- Kiểm tra các thông tin thông báo trên trang chủ','ACTIVE',2,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(3,'9fa3d6b7-07c9-4bf4-a36e-2925e7a792ef',18,1,'Đăng xuất','Chức năng cho phép người sử dụng thoát khỏi hệ thống khi đã đăng nhập trước ấy. Chức năng Bệnh án gồm các tính năng:\n- Đăng xuất khỏi hệ thông quản lý bệnh viện\n- Đăng xuất khỏi hệ thống ký điện tử đã đăng nhập trước đó','ACTIVE',3,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(4,'35549d45-2671-4207-b1ac-4004e51f051d',18,1,'Thiết lập khoa/ phòng','Chức năng cho phép người sử dụng thiết lập vào các khoa/ phòng để thực hiện các nghiệp vụ theo phạm vi khoa phòng đã định nghĩa trên hệ thống như: khám bệnh, điều trị ngoại trú, điều trị nội trú, thu viện phí, thực hiện cls, kê thuốc..... Chức năng Bệnh án gồm các tính năng:\n- Thiết lập khoa/ phòng \n- Hiển thị thông tin khoa/ phòng theo phân quyền người dùng\n- Chọn và thiết lập khoa phòng được chọn để thay đổi thông tin phòng thiết lập trên hệ thống','ACTIVE',4,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(5,'a0f07ad4-2fe5-4804-9dc6-b25bd4b365eb',18,1,'Đổi mật khẩu','Chức năng cho phép người sử dụng thay đổi mật khẩu đăng nhập mặc định, thay đổi định kỳ hoặc thay đổi khi đăng nhập bị lộ để đảm bảo an toàn bảo mật trên hệ thống đăng nhập vào hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Nhập mật khẩu cũ, mật khẩu hiện tại\n- Nhập thông tin mật khẩu mới \n- Nhập xác nhận lại mật khẩu mới với mật khẩu cần thay đổi\n- Xác nhận cập nhật thành công hoặc lỗi khi thay đổi thông tin theo chính sách mật khẩu được đưa ra','ACTIVE',5,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(6,'cd89914e-3950-4143-afbc-542e6cf949c7',18,1,'Quản lý khoa','Chức năng cho phép quản trị viên, nhân viên được phân công quản lý, thêm mới, thay đổi thông tin danh mục khoa/ trung tâm tại bệnh viện có thể bổ sung hoặc chỉnh sửa danh mục khoa tại bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin Danh mục khoa đã khai báo.\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới khoa chưa tồn tại trên hệ thống\n- Sửa khoa đang tồn tại trên hệ thống\n- Xóa khoa đang tồn tại trên hệ thống\n- Lưu khoa khi thêm mới hoặc khi sửa phòng\n- Hủy màn hình thêm mới, sửa khoa\n- Kiểm tra các thông tin bổ sung\n- Xuất danh sách khoa ra file excel','ACTIVE',6,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(7,'477a94a2-45ab-4c19-a099-6b90298d7b54',18,1,'Quản lý phòng','Chức năng cho phép quản trị viên, nhân viên được phân công quản lý, thay đổi hoặc thêm thông tin danh mục phòng theo khoa/ trung tâm tại bệnh viện.. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin Danh mục phòng đã khai báo.\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới phòng chưa có trên hệ thống\n- Sửa phòng đã có trên hệ thống\n- Xóa phòng đang tồn tại trên hệ thống\n- Lưu phòng khi thêm mới hoặc khi sửa phòng\n- Hủy màn hình thao tác chức năng phòng\n- Kiểm tra các thông tin bổ sung\n- Xuất danh sách phòng ra excel\n- Phân phòng thực hiện cho phòng Bệnh án được chọn để phân quyền trong các danh mục dịch vụ','ACTIVE',7,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(8,'dae8b1e4-8abd-419b-b842-d46fe7534b1b',18,1,'Quản lý nhân viên','Chức năng cho phép quản trị viên, nhân viên được phân công quản lý danh mục nhân viên của bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin Danh mục nhân viên đã khai báo.\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới nhân viên\n- Sửa nhân viên\n- Xóa nhân viên\n- Lưu nhân viên được thêm mới hoặc khi sửa nhân viên cũ\n- Hủy chức năng sửa hoặc thêm mới khi thay đổi\n- Upload/ xóa chữ ký\n- Kiểm tra các thông tin bổ sung\n- Check trạng thái hoạt động\n- Xuất danh sách nhân viên','ACTIVE',8,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(9,'80c84e8d-285a-411f-b1f3-5519a5d6483a',18,1,'Quản lý người dùng','Chức năng cho phép quản trị viên, nhân viên được phân công quản lý danh mục người dùng thêm mới hoặc thay đổi thông tin đăng nhập cho các nhân viên vào hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin Danh mục người dùng đã khai báo.\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới người dùng chưa có trên hệ thống\n- Sửa thông tin đăng nhập của người dùng trên hệ thống\n- Xóa thông tin đăng nhập của người dùng trên hệ thống\n- Lưu thông tin người dùng khi thêm mới hoặc sửa thông tin người dùng\n- Hủy thông tin sửa hoặc thêm mới khi sửa đổi\n- Kiểm tra các thông tin bổ sung\n- Xuất danh sách người dùng bằng excel\n- Đổi mật khẩu đăng nhập của người dùng vào hệ thống\n- Cài lại mật khẩu về mật khẩu mặc định vào hệ thống\n- Check trạng thái hoạt động\n- Phân quyền dữ liệu\n- Phân quyền menu\n- Phân quyền báo cáo\n- Phân quyền button chức năng','ACTIVE',9,9,9,'2026-03-31 04:03:45','2026-03-31 04:03:45',NULL),(10,'08c3125f-73d6-454e-a99c-101f6c35b7a0',18,1,'Danh mục cấu hình','Chức năng cho phép quản trị viên được phân quyền quản lý, thay đổi thông tin cấu hình luồng quy trình trên hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin danh mục cấu hình hệ thống đã khai báo (áp dụng cho Bệnh Viện).\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới thông tin cấu hình đã được khai báo trên site\n- Sửa giá trị tham số cấu hình có trong mô tả của cấu hình \n- Lưu giá trị khi thêm mới hoặc sửa đổi giá trị cấu hình\n- Hủy chức năng thêm mới hoặc sửa đổi\n- Danh mục cấu hình CSYT được quyền chỉnh sửa','ACTIVE',10,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(11,'0dd7756e-e4ba-40a3-a2ab-ec001ecf63b0',18,1,'Thêm mới cấu hình nhân viên','Chức năng cho phép quản trị viên được phân quyền quản lý, thay đổi thông tin cấu hình áp dụng đối với từng nhân viên truy cập vào hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin danh mục cấu hình nhân viên (áp dụng cho tài khoản nhân viên).\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới cấu hình nhân viên chưa có trên hệ thống\n- Sửa cấu hình nhân viên đã tồn tại trên hệ thống\n- Xóa cấu hình nhân viên đã tồn tại trên hệ thống\n- Lưu thông tin cấu hình khi sửa đổi hoặc thêm mới\n- Hủy chức năng khi thêm mới hoặc sửa đổi\n- Khôi phục lại trạng thái hoạt động của cấu hình khi bị xóa','ACTIVE',11,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(12,'55d98375-51fa-4c2f-af22-1a2b0071f8ab',18,1,'Danh mục cấu hình nhân viên','Chức năng cho phép nhân viên đăng nhập vào hệ thống cấu hình một số thông tin có trong danh mục cấu hình để thiết lập mặc định các giá trị trên các màn hình nghiệp vụ khi có nhu cầu. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin danh mục cấu hình nhân viên (áp dụng cho tài khoản).\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm mới cấu hình nhân viên đã được khai báo ở mục Thêm mới cấu hình nhân viên\n- Sửa danh mục cấu hình nhân đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc thông tin cấu hình đang sửa\n- Hủy chức năng khi thêm mới hoặc sửa đổi','ACTIVE',12,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(13,'51fdca9b-8920-4cc2-a2c8-e978e8a8dcb0',18,1,'Hệ thống menu','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin chức năng trên menu phân quyền cho nhóm người dùng truy cập vào hệ thống. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách menu chính hệ thống\n- Hiển thị danh sách chức năng theo menu chính\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Thêm chức năng chưa tồn tại trên hệ thống vào hệ thống menu \n- Sửa chức năng đã tồn tại trên hệ thống menu \n- Xóa chức năng đã tồn tại trên hệ thống menu\n- Lưu chức năng khi thêm mới hoặc sửa\n- Hủy màn hình nhập thông tin trên chức năng thêm mới hoặc sửa đổi','ACTIVE',13,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(14,'ce4075ca-db1a-48bc-b3ee-3233a77bb1a8',18,1,'Phân quyền chức năng menu','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin truy cập các màn hình nghiệp vụ cho nhóm người dùng được khai báo trên hệ thống. Chức năng Bệnh án gồm các tính năng\n- Hiển thị thông tin Danh sách nhóm người dùng.\n- Hiển thị danh sách menu đã cấp, chưa cấp theo người dùng\n- Cho phép tìm kiếm thông tin theo điều kiện.\n- Chọn hoặc bỏ chọn chức năng đã cấp chuyển sang chưa cấp\n- Chọn hoặc bỏ chọn chức năng chưa cấp chuyển sang đã cấp\n- Cập nhật (gen file menu)','ACTIVE',14,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(15,'9b891c0c-2e17-472b-bf3d-67f0542d1ff8',18,1,'Phân quyền dữ liệu người dùng','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi nhóm quyền dữ liệu của người dùng được phép truy cập vào hệ thống. Chức năng Bệnh án gồm các tính năng: \n- Tìm kiếm người dùng theo nhóm người dùng\n- Tìm kiếm danh sách người dùng theo khoa phòng nhân viên\n- Tìm kiếm nhanh trên lưới hiển thị\n- Chọn danh sách người dùng để phân quyền \n- Chọn danh sách nhóm quyền dữ liệu để phân hoặc bỏ phân quyền cho nhóm người dùng thao tác nghiệp vụ trên hệ thống','ACTIVE',15,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(16,'5cd3d8cf-3d44-42b8-89e6-7e4ba13538d4',18,2,'Danh mục quản lý địa danh','Chức năng cho phép quản lý, thay đổi thông tin địa danh mủa bệnh nhân trong quá trình khám chữa bệnh tại bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách địa danh khi khởi tạo\n- Tìm kiếm tên địa danh trong danh mục \n- Thêm xã mới chưa có trong hệ thống\n- Thêm huyện mới chưa có trên hệ thống\n- Sửa thông tin xã hoặc huyện đã có trên hệ thống\n- Xóa thông tin xã hoặc huyện đã có trên hệ thống\n- Lưu thông tin thêm mới xã, thêm mới huyện hoặc chỉnh sửa các thông tin xã hoặc huyện trên hệ thống\n- Hủy chức năng nhập thêm mới hoặc sửa thông tin xã, tỉnh','ACTIVE',1,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(17,'abbdc4f4-df46-4dab-8c81-779d897c2412',18,2,'Danh mục bệnh viện','Chức năng cho phép quản trị viên quản lý, thay đổi thông tin về danh mục các cơ sở y tế của BYT. Danh sách bệnh viện sẽ áp dụng trong tiếp nhận bệnh nhân có giấy chuyển tuyến, mã kcbbd hoặc sử dụng trong giấy chuyển tuyến đi cơ sở khác của bệnh viện, Chức năng Bệnh án gồm các tính năng\n- Hiển thị danh sách các bệnh viện.\n- Tìm kiếm thông tin bệnh viện.\n- Thêm mới một bệnh viên chưa có trên hệ thống.\n- Sửa một bệnh viên đã tồn tại trên hệ thống.\n- Xóa một bệnh viện đã tồn tại trên hệ thống.\n- Lưu thông tin thêm mới hoặc chỉnh sửa thông tin bệnh viện đã có sẵn.\n- Hủy thông tin thêm mới hoặc sửa hoăc thông tin bệnh viện.','ACTIVE',2,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(18,'ff94dd53-2bd0-4817-9ff3-952832358431',18,2,'Danh mục loại bệnh ICD','Chức năng cho phép quản trị viên quản lý, thay đổi danh mục loại bệnh ICD theo quy định của BYT. Chức năng Bệnh án gồm các tính năng\"\n- Hiển thị danh sách các mã bệnh ICD\n- Tìm kiếm thông tin bệnh trong danh mục\n- Thêm mới một mã bệnh ICD chưa có trên hệ thống \n- Sửa mã bệnh ICD đã tồn tại trên hệ thống\n- Xóa mã bệnh ICD đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc chỉnh sửa mã bệnh ICD trên hệ thống\n- Hủy thông tin thêm hoặc sửa danh mục mã bệnh ICD','ACTIVE',3,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(19,'b90fe95b-6997-4823-8d58-9d4a265fa147',18,2,'Danh mục đối tượng bhyt','Chức năng cho phép quản trị viên quản lý, thay đổi danh mục các đầu thẻ trong danh mục thẻ BHYT cấp phát thẻ cho người dân, thông tin gồm về tỷ lệ thanh toán, tỷ lệ hưởng tiền vận chuyển của bệnh nhân. Chức năng Bệnh án gồm các tính năng: \n- Hiển thị danh sách các đối tượng bhyt\n- Tìm kiếm thông tin bhyt trong danh mục\n- Thêm mới một đối tượng chưa có trên hệ thống\n- Sửa thông tin đối tượng bảo hiểm đã tồn tại trên hệ thống\n- Xóa thông tin đối tượng đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc chỉnh sửa đối tượng bhyt trên hệ thống\n- Hủy thông tin nhập khi thêm mới hoặc chỉnh sửa danh mục đối tượng BHYT','ACTIVE',4,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(20,'96696f7e-b691-4743-826f-87bb3c6e13db',18,2,'Danh mục thông báo','Chức năng cho phép quản trị viên, nhân viên của bệnh viện được phân công quản lý, thay đổi các thông báo mới đến các tài khoản người dùng trên hệ thống. Thông báo khi tạo ra sẽ được đưa lên trang chủ của bệnh viện. Danh mục thông báo Bệnh án gồm tính năng tạo bản ghi và file đính kèm và tạo thông báo text trên giao diện trang chủ. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh mục các thông báo đã chọn\n- Tìm kiếm thông tin thông báo\n- Thêm thông tin thông báo\n- Xóa thông tin thông báo đã có trên hệ thống\n- Tải tệp tin để đính kèm trong thông tin thông báo\n- Thêm mới một thông báo trên giao diện theo thứ tự hiển thi và theo ngày trên giao diện\n- Cập nhật thông tin thông báo đã có trên hệ thống\n- Xóa thông tin thông báo đã hết hạn','ACTIVE',5,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(21,'e562350b-6cd5-4670-b642-b1f253a6fc7f',18,2,'Danh mục dân tộc','Chức năng cho phép quản trị viên, nhân viên được phân công quản lý, thay đổi danh mục dân tộc theo quy định của nhà nước. Danh mục dân tộc trên hệ thống là danh mục theo quy định chung nên khi thay đổi cần phải thực tế theo quy định của nhà nước. Chức năng Bệnh án gồm các tính năng\n- Hiển thị danh sách các dân tộc đã khai báo\n- Tìm kiếm thông tin dân tộc trong danh mục\n- Thêm mới một dân tộc chưa có trên hệ thống\n- Sửa một dân tộc khi có thay đổi chung\n- Xóa một dân tộc khi bị thay đổi\n- Lưu thông tin thêm mới một dân tộc hoặc sửa danh mục dân tộc\n- Hủy thông tin giao diện khai báo','ACTIVE',6,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(22,'3e6f095a-8279-4424-8a95-ad45922f9d7b',18,2,'Danh mục mã nhóm dịch vụ','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục mã nhóm dịch vụ trong bệnh viên. Mã nhóm dịch vụ tương ứng với các màn hình danh mục tương ứng trên hệ thống. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách các mã nhóm dịch vụ\n- Tìm kiếm thông tin mã nhóm dịch vụ\n- Thêm mới một mã nhóm dịch vụ chưa có trên hệ thống\n- Sửa một danh mục dịch vụ đã có trên hệ thống\n- Xóa một danh mục nhóm dịch vụ đã có trên hệ thống\n- Lưu thông tin khi thêm mới hoặc sửa dịch vụ\n- Hủy thông tin giao diện khai báo thêm mới danh mục nhóm dịch vụ','ACTIVE',7,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(23,'fa202d18-d8d9-4992-b266-06651c59f485',18,2,'Danh mục khám bệnh','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục công khám theo danh mục được ban hành tại bệnh viện. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm bhxh, chuyên khoa, gói khám bệnh... Chức năng Bệnh án gồm các tính năng sau\n- Hiển thị danh sách dịch vụ khám bệnh\n- Tìm kiếm thông tin dịch vụ khám bệnh\n- Thêm mới một công khám chưa có trên hệ thống\n- Sửa thông tin các công khám đã tồn tại trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo các thông tư Bệnh án hành\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa thông tin công khám trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới hoặc sửa thông tin công khám đã có trên hệ thống\n- Hủy giao diện khai báo, chỉnh sửa thông tin công khám\n- Phân phòng thực hiện cho công khám được chọn để thực hiện các bản ghi khám bệnh cho bệnh nhân\n- Khoa thực hiện là áp dụng phân phòng thực hiện cho tất cả các phòng thuộc khoa trong danh mục\n- Chỉ định dịch vụ đi kèm công khám là tính năng cho phép chỉ định các dịch vụ khi tiếp nhận công khámd dược chọn.\n- Lưu các thông tin khi thêm mới, sửa, sửa giá mới, sao chép dịch vụ của công khám\n- Xuất danh sách dịch vụ dưới dạng excel để kểm tra hoặc lưu trữ thông tin','ACTIVE',8,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(24,'cd798062-dcdc-4a50-9d37-63e948c720c7',18,2,'Danh mục Xét nghiệm','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục xét nghiệm theo danh mục được Bệnh án hành tại viện. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm bhxh, chuyên khoa... Chức năng Bệnh án gồm các tính năng sau\n- Hiển thị danh sách dịch vụ xét nghiệm\n- Tìm kiếm thông tin dịch vụ khám bệnh\n- Thêm mới một danh mục xét nghiệm mới chưa có trên hệ thống\n- Sửa thông tin danh mục xét nghiệm đã có trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo các thông tư Bệnh án hành\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa thông tin xét nghiệm đã có trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới hoặc sửa thông tin xét nghiệm đã có trên hệ thống\n- Hủy giao diện khai báo, chỉnh sửa thông tin xét nghiệm\n- Phân Phòng thực hiện cho các xét nghiệm để thực hiện các dịch vụ theo nghiệp vụ khám chữa bệnh cho bệnh nhân\n- Phân khoa thực hiện cho các phòng thuộc vào khoa để thực hiện các dịch vụ theo nghiệp vụ khám chữa bệnh cho bệnh nhân\n- Cập nhật chỉ số con vào các chỉ định xét nghiệm để lấy chỉ số trả kết quả','ACTIVE',9,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(25,'af16ebd5-0b0b-49c0-961a-d687bf13a34f',18,2,'Danh mục thực hiện xét nghiệm','Chức năng cho phép quản trị viên, kỹ thuật viên, nhân viên được phân quyền quản lý, thay đổi thông tin các chỉ số con của xét nghiệm. Chức năng quản lý các thông tin chỉ số con, giá trị cận trên, cận dưới, đơn vị, mã dùng chung theo quy định của BYT, thứ tự thực hiện và hiển thị trên giao diện và phiếu in. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách các chỉ số xét nghiệm\n- Tìm kiếm thông tin chỉ số xét nghiệm\n- Thêm mới một chỉ số con chưa có trên hệ thống\n- Sửa một chỉ số con đã tồn tại trên hệ thống\n- Xóa một chỉ số con đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc thay đổi chỉ số con \n- Hủy thông tin khai báo trên giao diện','ACTIVE',10,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(26,'9141baae-405a-406c-88ca-f2e25739f0be',18,2,'Danh mục chẩn đoán hình ảnh','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục chẩn đoán hình ảnh theo danh mục được Bệnh án hành tại viện. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm BHXH, chuyên khoa... Chức năng Bệnh án gồm các tính năng sau\n- Hiển thị danh sách dịch vụ chẩn đoán hình ảnh\n- Tìm kiếm thông tin dịch vụ chẩn đoán hình ảnh\n- Thêm mới một danh mục chẩn đoán hình ảnh chưa có trên hệ thống\n- Sửa thông tin danh mục chẩn đoán hình ảnh đã có trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo các thông tư của Bệnh án \n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa thông tin chẩn đoán hình ảnh đã có trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới hoặc sửa thông tin chẩn đoán hình ảnh đã có trên hệ thống\n- Hủy giao diện khai báo thông tin chẩn đoán hình ảnh\n- Phân phòng thực hiện các dịch vụ chẩn đoán hình ảnh để thực hiện các dịch vụ theo nghiệm vụ khám chữa bệnh cho bệnh nhân\n- Phân khoa thực hiện cho các phòng thuộc vào khoa để thực hiện theo nghiệp vụ khám chữa bệnh','ACTIVE',11,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(27,'885e1721-569f-49ab-b7cc-86dd55bb2a54',18,2,'Danh mục mẫu kết quả thực hiện','Chức năng cho phép quản trị viên, kỹ thuật viên, bác sĩ người được phân quyền quản lý, thay đổi danh mục mẫu kết quả thực hiện danh mục chẩn đoán hình ảnh Các mẫu được tạo ra có thể thực hiện phân quyền chung theo nhóm hoặc theo dịch vụ. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách các mẫu kết quả chẩn đoán hình ảnh\n- Tìm kiếm thông tin mẫu kết quả chẩn đoán hình ảnh\n- Thêm mới một mẫu kết quả chưa có trên hệ thống\n- Sửa mẫu kết quả đã tồn tại trên hệ thống\n- Xóa mẫu kết quả đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc chỉnh sửa mẫu kết quả thực hiện\n- Hủy thông tin được khai báo trên giao diện danh mục','ACTIVE',12,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(28,'fbc85816-d802-42d6-9137-cdd283fab96b',18,2,'Danh mục phẫu thuật thủ thuật','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục phẫu thuật thủ thuật theo danh mục được Bệnh án hành tại viện. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm bhxh, chuyên khoa... Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ phẫu thuật thủ thuật\n- Tìm kiếm thông tin dịch vụ phẫu thuật thủ thuật\n- Thêm mới danh mục phẫu thuật thủ thuật chưa có trên hệ thống\n- Sửa danh mục phẫu thuật thủ thuật đã có trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo các thông tư Bệnh án hành\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa thông tin phẫu thuật thủ thuật đã có trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới hoặc sửa thông tin phẫu thuật thủ thuật đã có trên hệ thống\n- Hủy giao diện khai báo thông tin phẫu thuật thủ thuật\n- Phân phòng thực hiện cho các dịch vụ phẫu thuật thủ thuật để thực hiện các dịch vụ theo nghiệp vụ khám chữa bệnh cho bệnh nhân\n- Phân khoa thực hiện cho các phòng thuộc vào khoa để thực hiện theo nghiệp vụ khám chữa bệnh','ACTIVE',13,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(29,'dcc0a693-e36c-4ca8-8bad-b3ba4235a6ea',18,2,'Danh mục Suất ăn','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục suất ăn theo danh mục được Bệnh án hành tại viện. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ suất ăn\n- Tìm kiếm thông tin dịch vụ suất ăn\n- Thêm mới danh mục suất ăn chưa có trên hệ thống\n- Sửa danh mục suất ăn đã tồn tại trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo viện Bệnh án hành\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa thông tin suất ăn đã tồn tại trên hệ thống\n- Lưu các thông tin thêm mới, sao chép, sửa giá mới hoặc sửa thông tin danh mục suất ăn\n- Hủy giao diện khai báo thông tin suất ăn','ACTIVE',14,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(30,'9fcb28c6-34a2-4e17-a359-eaf893490f07',18,2,'Danh mục vận chuyển','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục vận chuyển mà bệnh viện chuyển đến khi chuyển viện. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm BHXH, chuyên khoa, khoảng cách di chuyển để cập nhật lại giá tiền thanh toán khi cập nhật giá xăng... Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ vận chuyển\n- Tìm kiếm thông tin dịch vụ vận chuyển\n- Thêm danh mục vận chuyển chưa có trên hệ thống\n- Sửa danh mục vận chuyển đã có trên hệ thống\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa danh mục vẫn chuyển đã có trên hệ thống\n- Lưu thông tin danh mục khi sửa đổi hoặc thêm mới\n- Hủy giao diện khai báo thông tin vận chuyển','ACTIVE',15,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(31,'b8ff6bde-3617-4288-b27d-34fa1d16c4f8',18,2,'Danh mục giá xăng','Chức năng cho phép quản trị viên, nhân viên kế toán được phân quyền quản lý, thay đổi thông tin giá xăng theo chu kỳ của bộ tài chính. Khi thay đổi giá xăng hệ thống sẽ tự động tính và cập nhật lại giá xăng trong danh mục vận chuyển để tính tiền cho bệnh nhân theo quy định. Chức năng Bệnh án gồm các tính năng sau\n- Hiển thị thông tin các dịch vụ vận chuyển được cập nhật\n- Tìm kiếm thông tin dịch vụ vận chuyển\n- Tìm kiếm lịch sử thay đổi giá vận chuyển\n- Sửa thông tin giá xăng\n- Lưu thông tin giá xăng và cập nhật giá trong danh mục vận chuyển\n- Hủy thông tin giao diện nhập','ACTIVE',16,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(32,'c8e40746-5a47-4b3a-b539-e269e3a4779c',18,2,'Danh mục ngày giường','Chức năng cho phép quản trị viên, nhân viên tài chính, phòng kế hoạch được phân quyền quản lý, thay đổi thông tin danh mục ngày giường điều trị mà bệnh viện được phê duyệt. Danh mục quản lý các thông tin như mã dùng chung, giá theo thông tư, nhóm bhxh, chuyên khoa,.... Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ ngày giường\n- Tìm kiếm thông tin dịch vụ ngày giường\n- Thêm mới danh mục ngày giường điều trj chưa có trên hệ thống\n- Sửa danh mục ngày giường điều trị đã có trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian theo các thông tư Bệnh án hành\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa danh mục ngày giường đã có trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới hoặc sửa thông tin ngày giường đã có trên hệ thống\n- Hủy giao diện khai báo thông tin ngày giường','ACTIVE',17,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(33,'19749f70-3de8-423b-be66-77fdc027c68a',18,2,'Danh mục phụ thu','Chức năng cho phép quản trị viên, nhân viên kế toán được phân quyền quản lý thay đổi thông tin danh mục phụ thu theo quy định của viện. Chức năng áp dụng khai báo cho chỉ định thu thêm tại các ca phẫu thuật thủ thuật cho bệnh nhân. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ phụ thu\n- Tìm kiếm thông tin dịch vụ phụ thu\n- Thêm mới danh mục phụ thu chưa có trên hệ thống\n- Sửa danh mục phụ thu đã tồn tại trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian của bệnh viên\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa danh mục phụ thu đã tồn tại trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới, sửa danh mục phụ thu\n- Hủy giao diện khai báo thông tin danh mục phụ thu','ACTIVE',18,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(34,'c7392c88-6931-441b-96ea-9a0bf5d265da',18,2,'Danh mục thu khác','Chức năng cho phép quản trị viên, nhân viên kế toán được phân quyền quản lý thay đổi thông tin danh mục thu khác theo quy định của viện. Chức năng áp dụng khai báo cho chỉ định thu ngoài danh mục khám chữa bệnh theo quy định tại. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách dịch vụ thu khác\n- Tìm kiếm thông tin dịch vụ thu khác\n- Thêm mới danh mục thu khác chưa có trên hệ thống\n- Sửa danh mục thu khác đã tồn tại trên hệ thống\n- Sửa giá mới là khai báo thêm giá được áp dụng theo thời gian của bệnh viên\n- Sao chép là lấy các thông tin theo danh mục được chọn để tạo mới cho một danh mục khác trên hệ thống\n- Xóa danh mục thu khác đã tồn tại trên hệ thống\n- Lưu các thông tin khi thêm mới, sao chép, sửa giá mới, sửa danh mục thu khác\n- Hủy giao diện khai báo thông tin danh mục thu khác','ACTIVE',19,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(35,'b3992454-6921-4488-b166-d366df67ad76',18,2,'Cấu hình dịch vụ cận lâm sàng','Chức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi cấu hình thứ tự ưu tiên phòng thực hiện của dịch vụ, đối với phòng thực hiện thì thứ tự ưu tiên sẽ là: phòng thiết lập, phòng của khoa, đến số thứ tự thiết lập. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị các dịch vụ cận lâm sàng\n- Xem thông tin dịch vụ\n- Set giá trị hiển thị phòng thực hiện\n- Lưu thông tin thứ tự phòng thực hiện\n- Xóa thông tin thứ tự phòng thực hiện\nChức năng cho phép quản trị viên, nhân viên được phân quyền quản lý, thay đổi thông tin danh mục khoa phòng và bác sĩ để bác sĩ thực hiện khám và điều trị ở nhiều phòng trong bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị thông tin khoa của bệnh viện\n- Tìm kiếm thông tin khoa cần phân quyền bác sĩ\n- Hiển thị thông tin khoa quản lý nhân viện\n- Tìm kiếm khoa bác sĩ\n- Chọn thông tin bác sĩ \n- Cập nhật thông tin bác sĩ vào khoa đã chọn','ACTIVE',20,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(36,'e4c8b76a-8077-447a-8015-91469270af62',18,2,'Danh mục khoa bác sĩ','Chức năng cho phép quản trị viên, nhân viên tại bệnh viện có thể khai báo và định nghĩa các danh mục báo cáo riêng cho cơ sở y tế mà dữ liệu không thể xử lý bằng mã nhóm trong danh mục cái dịch vụ, thuốc, vật tư. Lưu ý, các mã nhóm báo cáo sẽ luôn mặc định theo 1 mã báo cáo nhất định theo đơn vị. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh mục loại nhóm dịch vụ\n- Tìm kiếm loại nhóm dịch vụ\n- Thêm loại nhóm dịch vụ báo cáo mới\n- Sửa nhóm dịch vụ báo cáo có sẵn trên hệ thống\n- Xóa nhóm dịch vụ báo cáo đã có sẵn trên hệ thống\n- Lưu thông tin thêm mới hoặc chỉnh sửa nhóm báo cáo\n- Hủy giao diện khai báo thông tin danh mục loại nhóm dịch vụ\n- Kiểm tra trùng dịch vụ có thể cho 1 dịch vụ nằm ở nhiều nhóm hay không trên báo cáo','ACTIVE',21,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(37,'d7410651-8c1e-41ce-9edc-f1298b03d927',18,2,'Danh mục loại nhóm dịch vụ','Chức năng cho phép quản trị viên, nhân viên tại bệnh viện có thể khai báo và định nghĩa các danh mục báo cáo riêng cho cơ sở y tế mà dữ liệu không thể xử lý bằng mã nhóm trong danh mục cái dịch vụ, thuốc, vật tư. Lưu ý, các mã nhóm báo cáo sẽ luôn mặc định theo 1 mã báo cáo nhất định theo đơn vị. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh mục loại nhóm dịch vụ\n- Tìm kiếm loại nhóm dịch vụ\n- Thêm loại nhóm dịch vụ báo cáo mới\n- Sửa nhóm dịch vụ báo cáo có sẵn trên hệ thống\n- Xóa nhóm dịch vụ báo cáo đã có sẵn trên hệ thống\n- Lưu thông tin thêm mới hoặc chỉnh sửa nhóm báo cáo\n- Hủy giao diện khai báo thông tin danh mục loại nhóm dịch vụ\n- Kiểm tra trùng dịch vụ có thể cho 1 dịch vụ nằm ở nhiều nhóm hay không trên báo cáo','ACTIVE',22,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(38,'3c11413a-1cbd-4014-81e5-b1a4deac4e49',18,2,'Danh mục nhóm dịch vụ','Chức năng cho phép quản trị viên, nhân viên tại bệnh viện khai báo ra các mã nhóm báo cáo cần thực hiện trên báo cáo thống kê của đơn vị. Các nhóm dịch vụ sẽ tương ứng với các trường cần thống kê trên báo cáo. Nhóm dịch vụ báo cáo sẽ được maps vào loại nhóm dịch vụ báo cáo để phân loại và lọc dữ liệu. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh mục nhóm dịch vụ\n- Tìm kiếm danh mục nhóm dịch vụ\n- Thêm mới nhóm dịch vụ báo cáo chưa tồn tại trên hệ thống\n- Sửa nhóm dịch vụ báo cáo đã tồn tại trên hệ thống\n- Xóa nhóm dịch vụ báo cáo đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc sửa nhóm dịch vụ báo cáo\n- Hủy giao diện khai báo thông tin nhóm dịch vụ báo cáo','ACTIVE',23,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(39,'9b52e072-0951-4399-8e17-14790187ebc5',18,2,'Danh mục Loại Bệnh án','Chức năng cho phép quản trị viên, nhân viên bệnh viện thực hiện quản lý, thay đổi thông tin các loại Bệnh án mà bệnh viện thực hiện điều trị theo quy định. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách các loại Bệnh án trong danh mục\n- Tìm kiếm thông tin theo loại Bệnh án\n- Thêm mới một loại Bệnh án chưa có trên hệ thống nhưng đã Bệnh án hành trong các quyết định Bệnh án hành của BYT\n- Sửa một loại Bệnh án đã tồn tại trên hệ thống\n- Xóa một loại Bệnh án đã tồn tại trên hệ thống\n- Lưu thông tin thêm mới hoặc sửa đổi loại Bệnh án\n- Hủy giao diện khai báo thông tin loại Bệnh án\n- Khóa các loại Bệnh án không sử dụng','ACTIVE',24,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(40,'77578944-58f6-4063-ab63-5e54ebd04231',18,2,'Danh mục mã máy','Chức năng cho phép quản trị viên, kỹ thuật viên, bác sĩ, nhân viên bệnh viện được phân quyền quản lý, thay đổi thông tin mã máy các máy thực hiện các dịch vụ chẩn đoán hình ảnh xét nghiệm trên hệ thống để gửi hồ sơ lên cổng BHXH. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách mã máy đã khai báo\n- Tìm kiếm thông tin mã máy \n- Thêm mới mã máy chưa có trên hệ thống\n- Sửa mã máy đã tồn tại trên hệ thống\n- Xóa mã máy đã tồn tại trên hệ thống\n- Lưu mã máy được thêm mới hoặc chỉnh sửa\n- Hủy giao diện khai báo thông tin mã máy\n- Mở các mã máy đã khóa\n- Khóa các mã máy mà máy hỏng hoặc không sử dụng để tránh sai dữ liệu\n- Dm dịch vụ mã máy','ACTIVE',25,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(41,'8247f20e-9963-479f-9f2a-0c8bff9bd79d',18,2,'Danh mục dịch vụ mã máy','Chức năng cho phép quản trị viên, kỹ thuật viên, bác sĩ, nhân viên được phân quyền quản lý, thay đổi thông tin các dịch vụ theo máy thực hiện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách mã máy được khai báo\n- Tìm kiếm thông tin mã máy\n- Hiển thị thông tin dịch vụ\n- Tìm kiếm thông tin dịch vụ \n- Chọn dịch vụ được thực hiện bởi danh mục máy đã chọn\n- Cập nhật thông tin thay đổi dịch vụ theo mã máy\n- Set mã máy mặc định sẽ tự load tên máy khi thực hiện ở các màn hình chức năng\n- Cập nhật mã máy mặc định cho nhiều dịch vụ đã chọn','ACTIVE',26,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(42,'c352881f-acd0-4d5c-a4c1-eb51ab8b7a83',18,2,'Danh mục kho','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi thông tin về danh mục kho, cấu hình liên kết các kho trong bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách nhóm điều trị\n- Tìm kiếm thông tin từ giao diện quản lý\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới một kho chưa có trên hệ thống\n- Sửa thông tin cấu hình kho đã tồn tại trên hệ thống\n- Xuất excel danh sách các kho để kiểm tra\n- Chọn kho bù để thực hiện nghiệp vụ điều chuyển, luân chuyển thuốc vật tư\n- Phân khoa theo kho để nhìn thấy hoặc không nhìn thấy kho để lấy thuốc cho bệnh nhân\n- Phân đối tượng được lĩnh thuốc trong kho theo quy dịnh\n- Phân loại điều trị để xác định phạm vi và nghiệp vụ cung ứng thuốc cho khoa phòng\n- Phân nhóm cho kho để thực hiện phân rõ phạm vi và nghiệp vụ trong quản lý\n- Chọn nhóm thuốc mặc định maps thuốc vào kho\n- Lưu thông tin chỉnh sửa hoặc thêm mới kho\n- Lưu và đóng màn hình thông tin khai báo, cấu hình kho\n- Xóa kho khỏi hệ thống\n- Đóng màn hình cấu hình kho trong danh mục','ACTIVE',27,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(43,'fc385094-f530-46d9-a545-08ebe2f2063e',18,2,'Danh mục loại thuốc vật tư','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi danh mục loại thuốc, vật tư của bệnh viện. Chức năng cho phép cấu hình loại xuất theo phiếu, theo hạn.. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách các loại thuốc vật tư\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Sửa thông tin loại thuốc, vật tư \n- Lưu thông tin loại thuốc vật tư khi sửa đổi\n- Hủy giao diện nhập thông tin loại thuốc vật tư','ACTIVE',28,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(44,'92538ee1-d0f4-4df0-b8f6-7b9a2fe4f70c',18,2,'Danh mục nhà cung cấp','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi thông tin nhà cung cấp thuốc trong bệnh viện. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách các nhà cung cấp thuốc\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới danh mục nhà cung cấp\n- Sửa danh mục nhà cung cấp đã có trên hệ thống\n- Xóa danh mục nhà cung cấp đã có trên hệ thống\n- Lưu thông tin sửa đổi hoặc thêm mới danh mục nhà cung cấp \n- Hủy giao diện nhập thông tin danh mục nhà cung cấp\n- Khóa nhà cung cấp khi không còn sử dụng','ACTIVE',29,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(45,'ea0432d9-b605-46f7-8534-78f0eed46830',18,2,'Danh mục hoạt chất','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi thông tin hoạt chất, mã hoạt chất theo quy định của BYT. Chức năng Bệnh án gồm các tính năng\n- Hiển thị danh sách thông tin hoạt chất\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới mã hoạt chất mới theo quy định chưa có trên hệ thống\n- Sửa thông tin mã hoạt chất đã tồn tại trên hệ thống\n- Xóa thông tin mã hoạt chất đã tồn tại trên hệ thống\n- Lưu thông tin chỉnh sửa hoặc thêm mới mã hoạt chất\n- Hủy giao diện nhập thông tin danh mục hoạt chất\n- Khai báo danh mục tương tác hoạt chất để thực hiện cảnh báo tương tác thuốc khi kê\n- Khai báo hoạt chất tương đương để thực hiện quản lý danh mục cơ sổ tủ trực tại các khoa phòng','ACTIVE',30,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(46,'d46079db-f261-4543-8272-51b9910e3372',18,2,'Danh mục biệt dược','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi danh mục biệt dược theo quy định. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách thông tin biệt dược\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới danh mục biết dược theo quy định chưa có trên hệ thống\n- Sửa danh mục biệt dược đã có trên hệ thống\n- Xóa danh mục biệt dược đã có trên hệ thống\n- Lưu thông tin thay đổi hoặc thêm mới danh mục biệt dược\n- Hủy giao diện nhập danh mục biệt dược','ACTIVE',31,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(47,'552e8ceb-d713-4e56-b477-8b96f79f7441',18,2,'Danh mục đường dùng','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi danh mục đường dùng theo quy định của BYT. Chức năng còn quản lý mã đường dùng trong xml 4210 thanh toán cổng bhxh. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách thông tin đường dùng\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới danh mục đường dùng theo quy định chưa có trên hệ thống\n- Sửa danh mục đường dùng đã có trên hệ thống\n- Xóa danh mục đường dùng đã có trên hệ thống\n- Lưu thông tin thay đổi hoặc thêm mới danh mục đường dùng\n- Hủy giao diện nhập danh mục đường dùng','ACTIVE',32,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(48,'7f79125f-4e25-4645-bf4b-4d198cf7e64c',18,2,'Danh mục nước sản xuất','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi danh mục nước sản xuất, cung ứng thuốc cho đơn vị. Chức năng Bệnh án gồm các tính năng\n- Hiển thị danh sách nước sản xuất\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm mới danh mục nước sản xuất theo quy định chưa có trên hệ thống\n- Sửa danh mục nước sản xuất đã có trên hệ thống\n- Xóa danh mục nước sản xuất đã có trên hệ thống\n- Lưu thông tin sửa đổi hoặc thêm mới danh mục nước sản xuất\n- Hủy giao diện nhập nước sản xuất','ACTIVE',33,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(49,'1913dc5c-94c1-47cc-a47b-3a32309f3a81',18,2,'Danh mục hãng sản xuất','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi danh mục hãng sản xuất. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách hãng sản xuất\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm danh mục hãng sản xuất mới\n- Sửa danh mục hãng sản xuất đã tồn tại trên hệ thống\n- Xóa danh mục hãng sản xuất đã tồn tại trên hệ thống\n- Lưu thông tin sửa đổi hoặc thêm mới hãng sản xuất trên hệ thống\n- Hủy giao diện nhập hãng sản xuất','ACTIVE',34,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(50,'88f449f7-9f08-4844-9ba5-edc8902555b0',18,2,'Danh mục thuốc - vật tư','Chức năng cho phép quản trị viên, nhân viên, thủ kho quản lý danh mục thuốc, vật tư, hóa chất đang sửa dụng vào công tác khám chữa bệnh tại bệnh viện theo quyết định của BYT, sở y tế và BHXH áp dụng cho đơn vị được khai báo. Danh mục còn quản lý thông tin mã dùng chung, tên dùng chung, nhóm, thông tin thanh toán ... để thực hiện các nghiệp vụ thanh toán cho bệnh nhân. Chức năng Bệnh án gồm các tính năng\n- Hiển thị thông tin Danh mục thuốc đã khai báo.\n- Thêm mới danh mục thuốc vật tư chưa có trên hệ thống\n- Sửa danh mục thuốc vật tư đã có trên hệ thống\n- Kiểm tra trùng mã thuốc khi khai báo\n- Sao chép thuốc là sao chép thông tin thuốc đó để thêm mới 1 danh mục mới trên hệ thống\n- Import danh mục thuốc, vật tư\n- Xuất file Thuốc dạng excel để kiểm tra danh mục\n- Xuất file thuốc kèm thông tin thầu để kiểm tra thông tin \n- Tìm kiếm thông tin theo điều kiện lọc tại giao diện khai báo danh mục\n- Hiển thị danh sách theo nhóm thuốc cha, nhóm thuốc con\n- Chọn nhóm thuốc để khai báo thông tin thuốc được chọn\n- Chọn ICD để khai báo các thông tin cảnh báo thuốc theo ICD và tuổi khi kê cho bệnh nhân\n- Xem lịch sử thay đổi để kiểm tra thông tin và thời gian thay đổi trong danh mục\n- Lưu danh mục khi thêm mới, sao chép hoặc sửa\n- Lưu và đóng thông tin thêm mới, sao chép hoặc sửa đồng thời thoát popup khai báo thuốc\n- Xóa thuốc đã có trên hệ thống\n- Nhập thông tin thầu để xuất thanh toán xml theo 4210\n- Chọn kho để thực hiện gán các đầu thuốc vào kho cho các kho quản lý\n- Phân khoa chỉ định được danh mục thuốc đã khai báo để tránh nhầm lẫn trong điều trị\n- Khai báo danh mục tương tác thuốc để cảnh báo khi chỉ định cho bệnh nhân\n- Khai báo danh mục thuốc tương đương để quản lý cơ số tủ trực tại các khoa phòng khi thay đổi danh mục hoặc thuốc hết\n- Nhập thông tin thêm về quản lý yhct trong thanh toán cho bệnh nhân\n- Thêm thông tin lần thanh toán cho các vật tư đếm lần thanh toán như sten\n- Kiểm tra hiệu lực quyết định thầu theo thời gian và theo hợp đồng','ACTIVE',35,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(51,'43edbe1d-1013-4a59-8ff0-3284c93a36e7',18,2,'Quản lý kho - thuốc, vật tư','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi thông tin quản lý kho - thuốc trên hệ thống. Chức năng Bệnh án gồm các tính năng\n- Hiển thị thông tin nhóm thuốc vật tư\n- Chọn kho để thực hiện cấu hình thuốc quản lý\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Cấu hình thuốc vào kho để thực hiện các nghiệp vụ nhập xuất thuốc\n- Gỡ cấu hình thuốc, vật tư khi kho không quản lý danh mục thuốc, vật tư đã chọn\n- Định mức thuốc vật trong tủ trực\n- Lưu thông tin cấu hình','ACTIVE',36,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(52,'4e8a557f-9d86-4db0-99f2-be2f65240f25',18,2,'Hội đồng kiểm nhập','Chức năng cho phép quản trị viên, dược sĩ, thủ kho, nhân viên khoa dược được phân quyền quản lý, thay đổi hồi đổng kiểm nhập, hội đồng kiểm kê trong nhập kho nhà cung cấp. Chức năng gồm các tính năng sau\n- Hiển thị danh sách các hội đồng kiểm nhập\n- Tìm kiếm chi tiết các thông qua các trường trên giao diện của chức năng danh mục\n- Thêm hội đồng kiểm nhập, kiểm kê thuốc, vật tư, hóa chất mới\n- Sửa hội đồng kiểm nhập, kiểm kê\n- Xóa hội đồng kiểm nhập, kiểm kê\n- Thêm chức danh trong hội đồng\n- Sửa chức danh trong hội đồng\n- Xóa chức danh hội đồng\n- In hội đồng kiểm nhập','ACTIVE',37,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(53,'7fc870ca-abe1-4db6-b9f2-11e0d575fd99',18,2,'Danh mục đối tượng khám bệnh chữa bệnh','Chức năng cho phép quản trị hệ thống thêm thông tin đối tượng khám chữa bệnh tại bệnh viện. Chức năng gồm các tính năng:\n- Thêm mới\n- Chỉnh sửa\n- Xóa','ACTIVE',38,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(54,'84ea8b7c-f166-47f7-8552-4de49aa9e711',18,2,'Danh mục loại hình khám chữa bệnh','Chức năng cho phép quản trị hệ thống thêm thông tin loại hình khám chữa bệnh tại bệnh viện. Chức năng gồm các tính năng:\n- Thêm mới\n- Chỉnh sửa\n- Xóa','ACTIVE',39,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(55,'f6b147a6-398f-470f-9a43-629285bb1b96',18,2,'Danh mục chế độ chăm sóc','Chức năng cho phép điều dưỡng trưởng các khoa thêm sửa thông tin chế độ chăm sóc sử dụng tại Khoa điều trị, danh mục chế độ chăm sóc được sử dụng khi tạo phiếu chăm sóc. Chức năng gồm các tính năng:\n- Thêm mới\n- Chỉnh sửa\n- Xóa','ACTIVE',40,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(56,'244c874b-da83-426c-8509-0b38ae48cbf4',18,3,'Gọi bệnh nhân vào quầy tiếp nhận','Chức năng cho phép gọi thông tin bệnh nhân theo danh sách được cấp theo hệ thống xếp hàng tự động vào đăng ký khám chữa bệnh trên hệ thống. Chi tiết các tính năng sau:\n- Hiển thị số thứ tự tiếp nhận đang gọi đến.\n- Gọi số tiếp theo\n- Gọi từ số đến số\n- Gọi lại số các số đã được gọi nhưng bệnh nhân chưa vào tiếp nhận','ACTIVE',1,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(57,'e3b3b2d3-b95c-4f23-99e0-79f7dcc943cc',18,3,'Tiếp nhận đăng ký khám bệnh cho bệnh nhân','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế thực hiện tiếp nhận cho bệnh nhân theo danh sách được gọi từ hàng đợi tiếp nhận để đăng ký vào khám và điều trị cho bệnh nhân. Tại chức năng có quản lý thông tin lịch sử khám chữa bệnh của bệnh nhân, lịch sử hồ sơ tại cổng, kiểm tra thông tuyến khám chữa bệnh và một số nghiệp vụ còn chưa hoàn tất hoặc yêu cầu cảnh báo từ các lần khám chữa bệnh trước đó như: còn thuốc, chưa thanh toán, trốn viện... Chức năng Bệnh án gồm các tính năng sau: \n-Nhập thông tin hành chính của bệnh nhân\n- Tìm kiếm bệnh nhân bằng cách nhập mã bệnh nhân, mã Bệnh án hoặc bằng thẻ thông minh\n- Tìm kiếm bệnh nhân theo mã từ đầu đọc thẻ, số điện thoại\n- Cho phép tiếp nhận bệnh nhân bằng cách quét QR CODE thẻ BHYT/ VNEID/ VSSID\n- Nhập thông tin phòng khám đăng kí khám\n- Kiểm tra loại hình tiếp nhận\n- Chọn loại đối tượng tiếp nhận và nhập đầy đủ thông tin cần thiết cho đối tượng tiếp nhận\n- Nhập thông tin BHYT và kiểm tra thông tuyến từ cổng \n- Nhập thông tin chuyển tuyến từ tuyến dưới để hoàn tất các thủ tục thanh toán bhyt\n- Hiển thị lịch sử khám bệnh để kiểm tra khi tiếp nhận\n- Thực hiện chọn loại khám theo yêu cầu của bệnh nhân, và điều hướng phòng khám giảm tải bệnh nhân\n- Lưu thông tin tiếp nhận của bệnh nhân\n- In phiếu đăng ký khám và số thứ tự hàng đợi trong phòng khám cho bệnh nhân\n- Nhập bệnh nhân mới\n- Chụp ảnh chân dung để lưu hình ảnh làm bằng chứng trên hệ thống\n- Thông tin chuyển tuyến để hoàn tất công tác chuyên môn trên báo cáo chuyển đến\n- Kiểm tra thông tin bệnh nhân từ danh sách hẹn khám \n- Xem lịch sử KCB','ACTIVE',2,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(58,'bd24dedb-117f-429f-8562-ecff5e33155c',18,3,'Quản lý thông tin chuyển tuyến(giấy hẹn, giấy chuyển tuyến,…)','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế thực hiện nhập thông tin chuyển tuyến từ tuyến dưới cho bệnh nhân khám và điều trị tại bệnh viện mình nhằm đảm bảo hồ sơ thanh toán theo bhyt đúng theo quy định Bệnh án hành. Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị thông tin chuyển tuyến đã nhập \n- Nhập thông tin chuyển tuyến\n- Chọn hoặc bỏ chọn các thông tin chuyển tuyến theo quy định\n- Lưu thông tin chuyển tuyến\n- Đóng giao diện nhập thông tin chuyển tuyến.','ACTIVE',3,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(59,'d18a6b92-db6d-4ad2-9207-15e505b07c87',18,3,'Nhập thông tin sinh tồn','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế nhập các dấu hiệu sinh tồn Bệnh án đầu của bệnh nhân đo được trước khi đăng ký khám để bác sĩ biết và đánh giá tình trạng bệnh dễ dàng hơn. Chức nagnw Bệnh án gồmc các tính năng sau:\n- Cấu hình hiển thị giao diện không hiển thị giao diện\n- Hiển thị thông tin sinh tồn đã nhập \n- Nhập thông tin dấu hiệu sinh tồn\n- Tự động tính chỉ số BMI\n- Nhập thông tin tư vấn sản phụ khoa\n- Hiển thị danh sách lịch sử sản khoa.\n- Chọn và hiển thị thông tin lịch sử lên giao diện để kế thừa\n- Lưu thông tin dấu hiệu sinh tồn\n- Xóa thông tin dấu hiệu sinh tồn','ACTIVE',4,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(60,'da577c91-521d-4985-b678-efc987cff6b3',18,3,'In ấn','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế in hoặc in lại các giấy tờ theo quy định của bệnh viện tại chức năng tiếp nhận. Chức năng Bệnh án gồm các tính năng sau: \n- In Phiếu khám bệnh\n- In Bệnh ánrcode để dán lên sổ khám chữa bệnh hoặc in thẻ thông minh\n- Phiếu trả thẻ để xác nhận đã trả thẻ BHYT cho bệnh nhân\n- Phiếu chỉ định cận lâm sàng để bệnh nhân đi thực hiện cận lâm sàng trong trường hợp khám sức khỏe\n- In thẻ khám bệnh thông minh\n- In giấy chứng nhận sức khỏe','ACTIVE',5,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(61,'0b791e56-d0ab-4e0b-994b-88568dfb73cc',18,3,'Chỉ định dịch vụ cận lâm sàng','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế thực hiện chỉ định các gói dịch vụ như khám sức khỏe lái xe, đi làm ... theo yêu cầu của bệnh nhân\n- Hiển thị danh sách các dịch vụ để tạo phiếu chỉ định\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Tạo lưu thông tin mẫu phiếu để thực hiện nhanh cho các lần sau \n- Chọn phiếu mẫu để thực hiện chỉ định nhanh cho bệnh nhân\n- Hiển thị thông tin thanh toán\n- Lưu và in phiếu khi chỉ định\n- Lưu thông tin chỉ định\n- Đóng giao diện tạo phiếu chỉ định cận lâm sàng','ACTIVE',6,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(62,'c47c122b-b7bb-47ec-a428-9defb643a242',18,3,'Chỉ định thu khác','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế thực hiện chỉ định các dịch vụ ngoài danh mục khám chữa bệnh cần thu thêm cho bệnh nhân như: sổ khám bệnh, vòng đeo tay… Chức năng Bệnh án gồm các tính năng sau:\n- Hiển thị danh sách các dịch vụ thu khác để tạo phiếu chỉ định\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Tạo lưu thông tin mẫu phiếu để thực hiện nhanh cho các lần sau \n- Chọn phiếu mẫu để thực hiện chỉ định nhanh cho bệnh nhân\n- Hiển thị thông tin thanh toán\n- Lưu và in phiếu chỉ định\n- Lưu thông tin chỉ đinh\n- Đóng giao diện tạo phiếu chỉ định thu khác','ACTIVE',7,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(63,'b9555765-130e-4691-a029-3a8dc113ea79',18,3,'Danh sách xét nghiệm','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể kiểm tra thông tin các phiếu đã chỉ định và thông tin kết quả trả về từ hệ thống. Tại chức năng có thể thực hiện hủy phiếu, thay đổi các dịch vụ nếu có sai sót hoặc theo yêu cầu sau khi chỉ định. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách chi tiết phiếu xét nghiệm\n- Hiển thị thông tin chi tiết của các của phiếu xét nghiệm tương ứng với phiếu chỉ định được chọn được chọn\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Cho phép chọn cập nhật dịch vụ\n- Cho phép chọn xóa phiếu\n- Cho phép xóa các phiếu đã chọn\n- In phiếu xét nghiệm\n- Xem kết quả xét nghiệm','ACTIVE',8,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(64,'0b2e0bf3-e779-4e54-88f3-10df3324a33d',18,3,'Danh sách chẩn đoán hình ảnh','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể kiểm tra thông tin các phiếu đã chỉ định và thông tin kết quả trả về từ hệ thống. Tại chức năng có thể thực hiện hủy phiếu, thay đổi các dịch vụ nếu có sai sót hoặc theo yêu cầu sau khi chỉ định. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách chi tiết phiếu chẩn đoán hình ảnh\n- Hiển thị thông tin chi tiết của các dịch vụ phiếu chẩn đoán hình ảnh tương ứng với phiếu được chọn được chọn\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Cho phép chọn cập nhật dịch vụ\n- Cho phép chọn xóa phiếu\n- Cho phép xóa các phiếu đã chọn\n- In phiếu chẩn đoán hình ảnh','ACTIVE',9,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(65,'6cc06556-14dd-4574-b4e8-26d466ac0211',18,3,'Danh sách phẫu thuật thủ thuật','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể kiểm tra thông tin các phiếu đã chỉ định và thông tin kết quả trả về từ hệ thống. Tại chức năng có thể thực hiện hủy phiếu, thay đổi các dịch vụ nếu có sai sót hoặc theo yêu cầu sau khi chỉ định. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách chi tiết phiếu phẫu thuật thủ thuật\n- Hiển thị thông tin chi tiết các dịch vụ của phiếu phẫu thuật thủ thuật tương ứng với phiếu chỉ định được chọn\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Cho phép chọn cập nhật dịch vụ\n- Cho phép chọn xóa phiếu\n- Cho phép xóa các phiếu đã chọn\n- In phiếu phẫu thuật thủ thuật','ACTIVE',10,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(66,'d4e7d1a5-3200-499f-a4f8-1e2def5d596a',18,3,'Danh sách phiếu thu khác','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể kiểm tra thông tin các phiếu, các dịch vụ thu khác đã chỉ định cho bệnh nhân trên hệ thống. Tại chức năng có thể thực hiện hủy phiếu, thay đổi các dịch vụ thu khác nếu có sai sót hoặc theo yêu cầu sau khi chỉ định. Chức năng gồm các tính năng sau:\n- Hiển thị danh sách chi tiết phiếu tạo thu khác\n- Hiển thị thông tin chi tiết các dịch vụ của phiếu thu khác tương ứng với phiếu được chọn\n- Tìm kiếm thông tin chi tiết theo các thông tin hiển thị trên lưới.\n- Cho phép chọn cập nhật dịch vụ\n- Cho phép chọn xóa phiếu\n- Cho phép xóa các phiếu đã chọn\n- In phiếu thu khác','ACTIVE',11,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(67,'96415ba8-2b36-4672-bf9e-715faed8e4c0',18,3,'Danh sách hẹn khám','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể kiểm tra thông tin hoặc danh sách hẹn khám của các bệnh nhân đã phát sinh lịch hẹn ở các lần đăng ký khám chữa bệnh trước đó. Chức năng Bệnh án gồm các tính năng sau\n- Hiện thị danh sách bệnh nhân có hẹn khám\n- Tìm kiếm theo điều kiện trên giao diện\n- Chọn bệnh nhân để tiếp đón tiếp\n- Đóng giao diện hiển thị danh sách lịch hẹn','ACTIVE',12,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(68,'bb39ba42-03f8-4be6-9a18-9151c5a65366',18,3,'Quản lý chụp ảnh bệnh nhân','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể chụp ảnh, scan các ảnh giấy tờ của bệnh nhân để lưu trên hệ thống và có thể sử dụng để dối chiếu các lần khám sau\n- Hiển thị danh sách ảnh đã chụp\n- Chụp ảnh bệnh nhân\n- Chụp quyết định hưu\n- Lưu vào hệ thống\n- Đóng màn hình chụp ảnh','ACTIVE',13,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(69,'8aff7e82-9dcc-4eb2-ae41-2ace80e0389f',18,3,'Cập nhật công khám / phòng khám','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận có thể thay đổi công khám, phòng khám theo yêu cầu của bệnh nhân hoặc điều chỉnh thông tin phòng khám để giảm tải cho các phòng khám. Chức năng gồm các tính năng:\n- Hiển thị danh sách công khám theo bệnh nhân\n- Đổi phòng khám, công khám\n- Cập nhật lại công khám phòng khám\n- In phiếu lại phiếu hàng chờ khám bệnh\n- Đóng giao diện cập nhật công khám/ phòng khám','ACTIVE',14,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(70,'d9241ab3-37fd-4060-ab86-79eb238c062a',18,3,'Xóa bệnh nhân','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận xóa thông tin bệnh nhân đăng ký khám tại hệ thống khi có yêu cầu từ người bệnh khi chưa thực hiện khám tại các phòng khám. Chức năng Bệnh án gồm các tính năng:\n- Xóa bệnh nhân\n- Bật thông báo các điều kiện ràng buộc\n- Xác nhận thao tác','ACTIVE',15,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(71,'68f6e34a-0c19-43d3-a989-8c4f951fae23',18,3,'Sinh số thứ tự ưu tiên','Chức năng cho phép bác sĩ, điều dưỡng, nhân viên tiếp đón sinh lại số khám tại hàng đợi khám bệnh cho bệnh nhân. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách phòng khám\n- Sinh số mới\n- In phiếu\n- Đóng giao diện Sinh số thứ tự ưu tiên','ACTIVE',16,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(72,'5a2d909e-ea20-4059-87ae-6e7e60c38d93',18,3,'In lại phiếu','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận in lại phiếu đăng ký khám theo yêu cầu của bệnh nhân. Chức năng Bệnh án gồm các tính năng:\n- Hiển thị danh sách phòng khám\n- Sinh số mới\n- In lại phiếu đăng ký khám\n- Đóng giao diện in lại phiếu','ACTIVE',17,9,9,'2026-03-31 04:03:46','2026-03-31 04:03:46',NULL),(73,'4a2bb453-3aac-49e8-8366-d017013fc949',18,3,'Kiểm tra lịch sử KCB từ cổng BHYT','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận kiểm tra thông tin thẻ, thông tin lịch sử thông tuyến của bệnh nhân từ API trả về từ cổng giám định BHXH. Chức năng Bệnh án gồm các tính năng: \n- Hiển thị thông tin lịch sử điều trị đã được các cơ sở y tế gửi lên cổng \n- Tìm kiếm thông tin\n- Tìm kiếm thông tin chi tiết của bệnh nhân theo các trường thông tin trên giao diện tra cứu cổng BHXH\n- In thông tin thông tuyến\n- Đóng giao diện tra cứu thông tuyến','ACTIVE',18,9,9,'2026-03-31 04:03:47','2026-03-31 04:03:47',NULL),(74,'a567771f-0329-4fc2-988c-c7e07edb0732',18,3,'Kiểm tra thẻ BH từ cổng BH trong giao diện tiếp nhận','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận lấy thông tin thẻ, thông tin hành chính của bệnh nhân từ cổng giám định BHXH dựa trên 3 tiêu chí: họ và tên, ngày tháng năm sinh và số thẻ hoặc mã sổ BHXH của người bệnh. Chức năng gồm các tính năng sau\n- Cảnh báo các thông tin thay đổi hoặc thông tin thẻ bằng popup cho người dùng kiểm tra\n- Đưa các thông tin vào các nhãn tương ứng trên giao diện tiếp đón\n- Kiểm tra lại thông tin khi lưu vào hệ thống khám chữa bệnh','ACTIVE',19,9,9,'2026-03-31 04:03:47','2026-03-31 04:03:47',NULL),(75,'15e88867-f247-4a62-9515-36ee72a004bc',18,3,'Chọn đối tượng bệnh nhân','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận xác định vào tiếp nhận đối tượng bệnh nhân theo phân vùng và thực hiện các phạm vi thanh toán viện phí ở các nghiệp vụ theo quy trình tiếp theo:\n- Chọn đối tượng bệnh nhân và tiếp nhận vào hệ thống','ACTIVE',20,9,9,'2026-03-31 04:03:47','2026-03-31 04:03:47',NULL),(76,'fe3b36a9-dc16-4c94-90c9-de107e12cad5',18,3,'Lịch sử khám chữa bệnh trong tỉnh','Chức năng cho phép điều dưỡng, bác sĩ, nhân viên y tế tại giao diện tiếp nhận kiểm tra thông tin khám chữa bệnh tại các cơ sở y tế trong tỉnh cùng sử dụng phần mềm của VNPT khi được cấu hình\n- Hiển thị thông tin khám chữa bệnh tại các cơ sở y tế \n- Kiểm tra và tìm kiếm thông tin\n- Đóng giao diện tra cứu thông tin khám chữa bệnh trong tỉnh','ACTIVE',21,9,9,'2026-03-31 04:03:47','2026-03-31 04:03:47',NULL);
