INSERT INTO `product_quotation_versions` VALUES (1,1,1,'default','FAILED','Báo giá Bệnh viện đa khoa khu vực Ngã Bảy 2026 03 31.docx','2026-03-31','Bệnh viện đa khoa khu vực Ngã Bảy','Cần Thơ','phục vụ triển khai các sản phẩm/dịch vụ theo nhu cầu của Quý đơn vị',10.00,90,'Giá cước trên đã bao gồm chi phí vận hành cơ bản và các dịch vụ có liên quan.\nGiá cước trên chưa bao gồm chi phí tích hợp với các phần mềm khác, tùy chỉnh chức năng đang có, phát triển chức năng mới hoặc chuyển đổi dữ liệu.\nCác yêu cầu ngoài phạm vi tiêu chuẩn sẽ được khảo sát và báo giá bổ sung theo khối lượng thực tế.\nBáo giá có hiệu lực trong vòng 90 ngày kể từ ngày ký.','Ông Phan Văn Rở - Giám đốc - Phòng Giải pháp 2 - Trung tâm Kinh doanh Giải pháp, số điện thoại: 0945.200.052./.','Trung tâm Kinh doanh Giải pháp - VNPT Cần Thơ rất mong nhận được sự ủng hộ từ Quý đơn vị và hân hạnh phục vụ!','GIÁM ĐỐC','TRUNG TÂM KINH DOANH GIẢI PHÁP','',38300000.00,3830000.00,42130000.00,'Bốn mươi hai triệu một trăm ba mươi nghìn đồng',0,'89e136cc60abecbdb75f58e7ec51a38f286817460c9bdc1cab2658741b5fcaa6','2026-03-31 06:36:45',9,'{\"source\": \"confirmed_print\", \"generated_extension\": \"docx\"}','2026-03-31 06:36:45'),(2,1,2,'default','FAILED','Báo giá Bệnh viện đa khoa khu vực Ngã Bảy 2026 03 31.docx','2026-03-31','Bệnh viện đa khoa khu vực Ngã Bảy','Cần Thơ','phục vụ triển khai các sản phẩm/dịch vụ theo nhu cầu của Quý đơn vị',10.00,90,'Giá cước trên đã bao gồm chi phí vận hành cơ bản và các dịch vụ có liên quan.\nGiá cước trên chưa bao gồm chi phí tích hợp với các phần mềm khác, tùy chỉnh chức năng đang có, phát triển chức năng mới hoặc chuyển đổi dữ liệu.\nCác yêu cầu ngoài phạm vi tiêu chuẩn sẽ được khảo sát và báo giá bổ sung theo khối lượng thực tế.\nBáo giá có hiệu lực trong vòng 90 ngày kể từ ngày ký.','Ông Phan Văn Rở - Giám đốc - Phòng Giải pháp 2 - Trung tâm Kinh doanh Giải pháp, số điện thoại: 0945.200.052./.','Trung tâm Kinh doanh Giải pháp - VNPT Cần Thơ rất mong nhận được sự ủng hộ từ Quý đ