DROP TABLE IF EXISTS `project_procedure_steps`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `project_procedure_steps` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `procedure_id` bigint unsigned NOT NULL,
  `template_step_id` bigint unsigned DEFAULT NULL,
  `step_number` int NOT NULL,
  `parent_step_id` bigint unsigned DEFAULT NULL,
  `phase` varchar(100) DEFAULT NULL,
  `phase_label` varchar(255) DEFAULT NULL COMMENT 'Tên giai đoạn tuỳ chỉnh theo dự án; fallback về PHASE_LABELS ở FE nếu null',
  `step_name` varchar(500) NOT NULL,
  `step_detail` text,
  `lead_unit` varchar(500) DEFAULT NULL,
  `support_unit` varchar(500) DEFAULT NULL,
  `expected_result` text,
  `duration_days` int DEFAULT '0',
  `progress_status` enum('CHUA_THUC_HIEN','DANG_THUC_HIEN','HOAN_THANH') NOT NULL DEFAULT 'CHUA_THUC_HIEN',
  `document_number` varchar(255) DEFAULT NULL,
  `document_date` date DEFAULT NULL,
  `actual_start_date` date DEFAULT NULL,
  `actual_end_date` date DEFAULT NULL,
  `step_notes` text,
  `sort_order` int NOT NULL DEFAULT '0',
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `project_procedure_steps_template_step_id_foreign` (`template_step_id`),
  KEY `project_procedure_steps_parent_step_id_foreign` (`parent_step_id`),
  KEY `idx_procedure_sort` (`procedure_id`,`sort_order`),
  KEY `idx_progress` (`procedure_id`,`progress_status`),
  CONSTRAINT `project_procedure_steps_parent_step_id_foreign` FOREIGN KEY (`parent_step_id`) REFERENCES `project_procedure_steps` (`id`) ON DELETE SET NULL,
  CONSTRAINT `project_procedure_steps_procedure_id_foreign` FOREIGN KEY (`procedure_id`) REFERENCES `project_procedures` (`id`) ON DELETE CASCADE,
  CONSTRAINT `project_procedure_steps_template_step_id_foreign` FOREIGN KEY (`template_step_id`) REFERENCES `project_procedure_template_steps` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=545 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

